# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, jsonify
from selenium import webdriver
from io import BytesIO
import boto3

app = Flask(__name__)

# Configure AWS S3 client
s3 = boto3.client('s3')

@app.route('/screenshot', methods=['POST'])
def generate_screenshot():
    try:
        # Get the URL from the request
        url = request.json['url']

        # Create a headless Chrome browser
        driver = webdriver.PhantomJS()
        driver.set_window_size(1280, 800)
        driver.get(url)

        # Take a screenshot
        screenshot = driver.get_screenshot_as_png()

        # Close the browser
        driver.quit()

        # Upload the screenshot to S3
        s3.put_object(Bucket='your-bucket-name', Key=f'screenshots/{url.replace("/", "_")}.png', Body=screenshot)

        # Return the screenshot URL
        return jsonify({'url': f'your-bucket-url/{url.replace("/", "_")}.png'})

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=80)